1	export interface Item {
2	  type: string;
3	  material?: string;
4	  enchantment?: number;
5	  cursed?: boolean;
6	}
7	
8	const CURSE_SURCHARGE = 0.5;
9	const FIRST_INSURANCE_SURCHARGE = 0.1;
10	const FOLLOW_UP_CONTRACT_DISCOUNT = 0.15;
11	const HIGH_ENCHANTMENT_SURCHARGE = 0.3;
12	const HIGH_ENCHANTMENT_THRESHOLD = 5;
13	const LOYALTY_DISCOUNT = 0.2;
14	const LOYALTY_YEARS_THRESHOLD = 2;
15	
16	export interface QuoteStep {
17	  op: "quote";
18	  items: Item[];
19	}
20	
21	export interface Damage {
22	  itemType: string;
23	  amount: number;
24	}
25	
26	export interface ClaimStep {
27	  op: "claim";
28	  policy: number;
29	  incident: {
30	    cause: string;
31	    damages: Damage[];
32	  };
33	}
34	
35	export type Step = QuoteStep | ClaimStep;
36	
37	export interface Scenario {
38	  customer: { yearsWithMHPCO: number };
39	  steps: Step[];
40	}
41	
42	export interface QuoteResult {
43	  premium: number;
44	}
45	
46	export interface ClaimResult {
47	  payout: number;
48	  remainingCap: number;
49	}
50	
51	export type StepResult = QuoteResult | ClaimResult;
52	
53	export interface ScenarioResult {
54	  results: StepResult[];
55	}
56	
57	const PROCESSING_FEE = 5;
58	
59	const BASE_PREMIUM: Record<string, number> = {
60	  sword: 100,
61	  amulet: 60,
62	  staff: 80,
63	  potion: 40,
64	  rune: 25,
65	  moonstone: 25,
66	};
67	
68	const INSURANCE_VALUE: Record<string, number> = {
69	  sword: 1000,
70	  amulet: 600,
71	  staff: 800,
72	  potion: 400,
73	  rune: 250,
74	  moonstone: 250,
75	};
76	
77	const DEDUCTIBLE = 100;
78	const CAP_MULTIPLIER = 2;
79	
80	const basePremiumFor = (item: Item): number => BASE_PREMIUM[item.type] ?? 0;
81	
82	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
83	const COMPONENT_BLOCK_SIZE = 3;
84	const COMPONENT_BLOCK_PRICE = 60;
85	
86	const groupByType = (items: Item[]): Map<string, Item[]> => {
87	  const groups = new Map<string, Item[]>();
88	  for (const item of items) {
89	    const group = groups.get(item.type) ?? [];
90	    group.push(item);
91	    groups.set(item.type, group);
92	  }
93	  return groups;
94	};
95	
96	const isHighlyEnchanted = (item: Item): boolean =>
97	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
98	
99	const itemSurchargeFactor = (item: Item): number =>
100	  (item.cursed ? CURSE_SURCHARGE : 0) +
101	  (isHighlyEnchanted(item) ? HIGH_ENCHANTMENT_SURCHARGE : 0);
102	
103	const itemSurchargeAmount = (item: Item): number =>
104	  basePremiumFor(item) * itemSurchargeFactor(item);
105	
106	const groupBaseCost = (type: string, group: Item[]): number => {
107	  if (COMPONENT_TYPES.has(type) && group.length === COMPONENT_BLOCK_SIZE) {
108	    return COMPONENT_BLOCK_PRICE;
109	  }
110	  return group.reduce((sum, item) => sum + basePremiumFor(item), 0);
111	};
112	
113	const policyBase = (items: Item[]): number =>
114	  Array.from(groupByType(items)).reduce(
115	    (sum, [type, group]) => sum + groupBaseCost(type, group),
116	    0,
117	  );
118	
119	const itemSurchargesTotal = (items: Item[]): number =>
120	  items.reduce((sum, item) => sum + itemSurchargeAmount(item), 0);
121	
122	const policyModifierFactor = (
123	  customer: { yearsWithMHPCO: number },
124	  isFollowUp: boolean,
125	): number =>
126	  FIRST_INSURANCE_SURCHARGE -
127	  (customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD ? LOYALTY_DISCOUNT : 0) -
128	  (isFollowUp ? FOLLOW_UP_CONTRACT_DISCOUNT : 0);
129	
130	const quote = (
131	  items: Item[],
132	  customer: { yearsWithMHPCO: number },
133	  isFollowUp: boolean,
134	): QuoteResult => {
135	  const base = policyBase(items);
136	  const itemSurcharges = itemSurchargesTotal(items);
137	  const policyModifiers = base * policyModifierFactor(customer, isFollowUp);
138	  return {
139	    premium: Math.ceil(base + itemSurcharges + policyModifiers + PROCESSING_FEE),
140	  };
141	};
142	
143	interface Policy {
144	  items: Item[];
145	  insuranceSum: number;
146	  remainingCap: number;
147	}
148	
149	const policyInsuranceSum = (items: Item[]): number =>
150	  items.reduce((sum, item) => sum + (INSURANCE_VALUE[item.type] ?? 0), 0);
151	
152	const createPolicy = (items: Item[]): Policy => {
153	  const insuranceSum = policyInsuranceSum(items);
154	  return {
155	    items,
156	    insuranceSum,
157	    remainingCap: insuranceSum * CAP_MULTIPLIER,
158	  };
159	};
160	
161	const HIGH_ENCHANTMENT_CLAIM_THRESHOLD = 8;
162	const HIGH_ENCHANTMENT_CLAIM_FACTOR = 0.5;
163	
164	const damagePayout = (item: Item | undefined, amount: number): number => {
165	  const reimbursable =
166	    item && (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_CLAIM_THRESHOLD
167	      ? amount * HIGH_ENCHANTMENT_CLAIM_FACTOR
168	      : amount;
169	  return Math.max(0, reimbursable - DEDUCTIBLE);
170	};
171	
172	const findItemForDamage = (items: Item[], damage: Damage): Item | undefined =>
173	  items.find((item) => item.type === damage.itemType);
174	
175	const claimPayout = (policy: Policy, damages: Damage[]): number =>
176	  damages.reduce(
177	    (sum, damage) =>
178	      sum + damagePayout(findItemForDamage(policy.items, damage), damage.amount),
179	    0,
180	  );
181	
182	const processClaim = (policy: Policy, step: ClaimStep): ClaimResult => {
183	  const payout = claimPayout(policy, step.incident.damages);
184	  return { payout, remainingCap: policy.remainingCap - payout };
185	};
186	
187	interface ScenarioState {
188	  policies: Policy[];
189	  results: StepResult[];
190	}
191	
192	const applyStep = (
193	  state: ScenarioState,
194	  step: Step,
195	  customer: { yearsWithMHPCO: number },
196	): ScenarioState => {
197	  if (step.op === "quote") {
198	    const isFollowUp = state.policies.length > 0;
199	    return {
200	      policies: [...state.policies, createPolicy(step.items)],
201	      results: [...state.results, quote(step.items, customer, isFollowUp)],
202	    };
203	  }
204	  const claimResult = processClaim(state.policies[step.policy], step);
205	  const updatedPolicy: Policy = {
206	    ...state.policies[step.policy],
207	    remainingCap: claimResult.remainingCap,
208	  };
209	  return {
210	    policies: state.policies.map((p, i) =>
211	      i === step.policy ? updatedPolicy : p,
212	    ),
213	    results: [...state.results, claimResult],
214	  };
215	};
216	
217	export const runScenario = (scenario: Scenario): ScenarioResult => {
218	  const finalState = scenario.steps.reduce<ScenarioState>(
219	    (state, step) => applyStep(state, step, scenario.customer),
220	    { policies: [], results: [] },
221	  );
222	  return { results: finalState.results };
223	};
